import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

function App() {
  // Controle de Telas: 'home', 'criar', ou 'detalhes'
  const [view, setView] = useState('home');
  const [campeonatos, setCampeonatos] = useState([]);
  
  // Estados para Criação de Campeonato
  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos');
  const [qtdTimes, setQtdTimes] = useState(16);

  // === NOVOS ESTADOS PARA A TELA DE DETALHES E TIMES ===
  const [campeonatoAtivo, setCampeonatoAtivo] = useState(null);
  const [times, setTimes] = useState([]);
  const [nomeTime, setNomeTime] = useState('');
  const [nomeResponsavel, setNomeResponsavel] = useState('');

  // 1. Carregar Campeonatos
  const carregarCampeonatos = async () => {
    const { data, error } = await supabase
      .from('campeonatos')
      .select('*')
      .order('created_at', { ascending: false });
    if (!error) setCampeonatos(data);
  };

  useEffect(() => {
    carregarCampeonatos();
  }, []);

  // 2. Criar Campeonato
  const criarCampeonatoReal = async (e) => {
    e.preventDefault();
    const { error } = await supabase
      .from('campeonatos')
      .insert([{ nome, formato, qtd_times: qtdTimes }]);

    if (!error) {
      setNome(''); setFormato('pontos-corridos'); setQtdTimes(16);
      carregarCampeonatos();
      setView('home'); 
    }
  };

  // === NOVAS FUNÇÕES PARA TIMES ===

  // Entrar em um campeonato específico
  const abrirDetalhes = async (campeonato) => {
    setCampeonatoAtivo(campeonato);
    setView('detalhes');
    carregarTimes(campeonato.id);
  };

  // Buscar os times daquele campeonato no Supabase
  const carregarTimes = async (campeonatoId) => {
    const { data, error } = await supabase
      .from('times')
      .select('*')
      .eq('campeonato_id', campeonatoId)
      .order('created_at', { ascending: true });
    
    if (!error) setTimes(data);
  };

  // Cadastrar um novo time
  const adicionarTime = async (e) => {
    e.preventDefault();
    
    // Trava para não adicionar mais times que o limite do campeonato
    if (times.length >= campeonatoAtivo.qtd_times) {
      alert(`O limite de ${campeonatoAtivo.qtd_times} times já foi atingido!`);
      return;
    }

    const { error } = await supabase
      .from('times')
      .insert([{ 
        campeonato_id: campeonatoAtivo.id, 
        nome: nomeTime, 
        jogador_responsavel: nomeResponsavel 
      }]);

    if (!error) {
      setNomeTime('');
      setNomeResponsavel('');
      carregarTimes(campeonatoAtivo.id); // Recarrega a lista na hora
    }
  };

  // Deletar um time
  const removerTime = async (timeId) => {
    const { error } = await supabase
      .from('times')
      .delete()
      .eq('id', timeId);
    
    if (!error) carregarTimes(campeonatoAtivo.id);
  };

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans">
      {/* NAVBAR */}
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card">
        <h1 
          className="text-2xl font-bold italic text-ef-green cursor-pointer" 
          onClick={() => setView('home')}
        >
          eFOOTBALL CHAMP
        </h1>
        <div className="space-x-6">
          <button onClick={() => setView('home')} className="hover:text-ef-green transition">Campeonatos</button>
          <button className="bg-ef-green text-black px-4 py-2 rounded-full font-bold hover:bg-green-400 transition">Entrar</button>
        </div>
      </nav>

      <main className="p-8 max-w-6xl mx-auto">
        
        {/* === TELA 1: HOME (LISTA DE CAMPEONATOS) === */}
        {view === 'home' && (
          <>
            <header className="mb-10">
              <h2 className="text-4xl font-extrabold">Gerencie seus Torneios</h2>
              <p className="text-gray-400 mt-2">Selecione um campeonato para gerenciar times e partidas.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {campeonatos.map((champ) => (
                <div key={champ.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition-all">
                  <div className="bg-ef-green text-black text-xs font-bold px-2 py-1 rounded inline-block mb-4">OPEN</div>
                  <h3 className="text-xl font-bold mb-2">{champ.nome}</h3>
                  <p className="text-gray-400 text-sm">{champ.qtd_times} Times • {champ.formato.replace('-', ' ')}</p>
                  
                  {/* Botão que agora abre a tela de detalhes */}
                  <button 
                    onClick={() => abrirDetalhes(champ)}
                    className="mt-6 w-full py-2 border border-ef-green text-ef-green rounded-lg hover:bg-ef-green hover:text-black transition"
                  >
                    Gerenciar Torneio
                  </button>
                </div>
              ))}
              
              <div 
                onClick={() => setView('criar')}
                className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex flex-col items-center justify-center text-gray-500 hover:text-ef-green hover:border-ef-green transition cursor-pointer"
              >
                 <span className="text-4xl mb-2">+</span>
                 <p className="font-bold">Criar Campeonato</p>
              </div>
            </div>
          </>
        )}

        {/* === TELA 2: CRIAR CAMPEONATO (Mantida igual) === */}
        {view === 'criar' && (
           <div className="max-w-2xl mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
             <h2 className="text-3xl font-bold mb-6 border-b border-gray-800 pb-4">Novo Campeonato</h2>
             <form onSubmit={criarCampeonatoReal} className="space-y-6">
               <div>
                 <label className="block text-gray-400 mb-2">Nome do Campeonato</label>
                 <input type="text" required value={nome} onChange={(e) => setNome(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition" placeholder="Ex: Copa eFootball Brasil" />
               </div>
               <div className="grid grid-cols-2 gap-6">
                 <div>
                   <label className="block text-gray-400 mb-2">Formato</label>
                   <select value={formato} onChange={(e) => setFormato(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition">
                     <option value="pontos-corridos">Pontos Corridos (Liga)</option>
                     <option value="mata-mata">Mata-Mata (Copa)</option>
                   </select>
                 </div>
                 <div>
                   <label className="block text-gray-400 mb-2">Quantidade de Times</label>
                   <input type="number" min="2" max="64" required value={qtdTimes} onChange={(e) => setQtdTimes(e.target.value)} className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green transition" />
                 </div>
               </div>
               <div className="flex space-x-4 pt-4">
                 <button type="button" onClick={() => setView('home')} className="flex-1 py-3 border border-gray-600 text-gray-400 rounded-lg hover:bg-gray-800 transition">Cancelar</button>
                 <button type="submit" className="flex-1 py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 transition">Salvar Torneio</button>
               </div>
             </form>
           </div>
        )}

        {/* === TELA 3: DETALHES DO CAMPEONATO E TIMES === */}
        {view === 'detalhes' && campeonatoAtivo && (
          <div>
            <button onClick={() => setView('home')} className="text-gray-400 hover:text-ef-green mb-6 flex items-center">
              ← Voltar para todos os campeonatos
            </button>
            
            <header className="mb-10 pb-6 border-b border-gray-800 flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-extrabold text-ef-green">{campeonatoAtivo.nome}</h2>
                <p className="text-gray-400 mt-2">Formato: {campeonatoAtivo.formato.replace('-', ' ')} • Limite: {campeonatoAtivo.qtd_times} times</p>
              </div>
              <div className="text-right">
                <p className="text-sm text-gray-400">Vagas Preenchidas</p>
                <p className="text-3xl font-bold">{times.length} / {campeonatoAtivo.qtd_times}</p>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              
              {/* Coluna da Esquerda: Formulário de Adicionar Time */}
              <div className="md:col-span-1 bg-ef-card p-6 rounded-2xl border border-gray-800 h-fit">
                <h3 className="text-xl font-bold mb-4">Adicionar Time</h3>
                <form onSubmit={adicionarTime} className="space-y-4">
                  <div>
                    <label className="block text-sm text-gray-400 mb-1">Nome do Time</label>
                    <input 
                      type="text" required value={nomeTime} onChange={(e) => setNomeTime(e.target.value)}
                      className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green" 
                      placeholder="Ex: Flamengo"
                    />
                  </div>
                  <div>
                    <label className="block text-sm text-gray-400 mb-1">Jogador (Psn/Gamertag)</label>
                    <input 
                      type="text" required value={nomeResponsavel} onChange={(e) => setNomeResponsavel(e.target.value)}
                      className="w-full bg-ef-dark border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-ef-green" 
                      placeholder="Ex: Joãozinho_GamePlay"
                    />
                  </div>
                  <button 
                    type="submit" 
                    disabled={times.length >= campeonatoAtivo.qtd_times}
                    className="w-full py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 disabled:opacity-50 disabled:cursor-not-allowed transition"
                  >
                    Cadastrar Time
                  </button>
                </form>
              </div>

              {/* Coluna da Direita: Lista de Times Cadastrados */}
              <div className="md:col-span-2">
                <h3 className="text-xl font-bold mb-4">Times Cadastrados ({times.length})</h3>
                
                {times.length === 0 ? (
                  <div className="text-center text-gray-500 py-10 border border-dashed border-gray-800 rounded-2xl">
                    Nenhum time cadastrado ainda. Comece adicionando ao lado!
                  </div>
                ) : (
                  <div className="space-y-3">
                    {times.map((time) => (
                      <div key={time.id} className="bg-ef-card p-4 rounded-xl border border-gray-800 flex justify-between items-center hover:border-gray-600 transition">
                        <div>
                          <p className="font-bold text-lg">{time.nome}</p>
                          <p className="text-sm text-gray-400 block">🎮 {time.jogador_responsavel}</p>
                        </div>
                        <button 
                          onClick={() => removerTime(time.id)}
                          className="text-red-500 hover:text-red-400 text-sm p-2"
                        >
                          Remover
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

            </div>
          </div>
        )}

      </main>
    </div>
  );
}

export default App;
